import React, { useState, useEffect, useRef } from 'react';
import {
  Globe,
  MessageSquare,
  Eye,
  PenSquare,
  ArrowLeft,
  Image as ImageIcon,
  Send,
  User,
  TrendingUp,
  Menu,
  ChevronDown,
  Zap,
  Video,
  Smile,
  Bold,
  Italic,
  Underline as UnderlineIcon,
  AlignLeft,
  AlignCenter,
  AlignRight,
  Palette,
  Highlighter,
} from 'lucide-react';

// Tiptap 3 Imports (Named Exports)
import { useEditor, EditorContent } from '@tiptap/react';
import { BubbleMenu } from '@tiptap/react/menus';
import { StarterKit } from '@tiptap/starter-kit';
import { Image } from '@tiptap/extension-image';
import { Youtube } from '@tiptap/extension-youtube';
import { Placeholder } from '@tiptap/extension-placeholder';
import { TextAlign } from '@tiptap/extension-text-align';
import { Underline } from '@tiptap/extension-underline';
import { Color } from '@tiptap/extension-color';
import { Highlight } from '@tiptap/extension-highlight';
import { TextStyle } from '@tiptap/extension-text-style';
import { getActiveApiKey } from '../apiUtils';
import { translateContent } from '../communityAiService';
import {
  getPostsByCategory,
  getPostDetail,
  createPost,
  getCommentsByPost,
  createComment,
  uploadCommunityImage,
  getGlobalPopularPosts,
  type CommunityPost,
  type CommunityComment
} from '../communityService';
import { getFlagEmoji } from '../utils/langUtils';
import { PcAdSlot } from '../components/PcComponents';


interface CommunityForumProps {
  lang: string;
  firebaseUser: { uid: string; displayName?: string | null; photoURL?: string | null; [key: string]: unknown } | null;
  onBack?: () => void;
  externalPostId?: string;
}

const CATEGORY_GROUPS = [
  {
    id: 'MAIN_LOUNGE',
    label_ko: '硫붿씤 ?뚰넻諛?,
    label_en: 'Main Lounge',
    icon: <Globe size={16} />,
    items: [
      { id: 'ALL', name_ko: '?꾩껜 ?쇰뱶', name_en: 'All Feeds', icon: '?뙋' },
      { id: 'HOT', name_ko: '?ㅼ떆媛?踰좎뒪??, name_en: 'Hot Issues', icon: '?뵦' },
      { id: 'FREE', name_ko: '?먯쑀/?쇱긽', name_en: 'Free Talk', icon: '?뮠' },
      { id: 'STUDY', name_ko: '?곸뼱 Q&A 諛??숈뒿 ??, name_en: 'Study & Tips', icon: '?뱴' },
      { id: 'MEDIA', name_ko: '誘몃뵒???륂뤌', name_en: 'Media & Shorts', icon: '?렗' },
      { id: 'EXCHANGE', name_ko: '?몄뼱 援먰솚/移쒓뎄 李얘린', name_en: 'Language Exchange', icon: '?쩃' },
      { id: 'PROMO', name_ko: '?띾낫/嫄댁쓽?ы빆', name_en: 'Promo & Feedback', icon: '?뱼' },
    ]
  }
];

const getCategoryName = (id: string, lang: string) => {
  for (const group of CATEGORY_GROUPS) {
    const item = group.items.find(i => i.id === id);
    if (item) return (item as any)[`name_${lang}` as 'name_ko' | 'name_en'];
  }
  return id;
};

export const CommunityForumScreen = ({ lang, firebaseUser, externalPostId }: CommunityForumProps) => {
  const [view, setView] = useState<'LIST' | 'DETAIL' | 'WRITE'>(() => {
    return (localStorage.getItem('vq_forum_view') as 'LIST' | 'DETAIL' | 'WRITE') || 'LIST';
  });
  const [selectedCategory, setSelectedCategory] = useState(() => {
    return localStorage.getItem('vq_forum_category') || 'ALL';
  });
  const [posts, setPosts] = useState<CommunityPost[]>([]);
  const [selectedPost, setSelectedPost] = useState<CommunityPost | null>(null);
  const [comments, setComments] = useState<CommunityComment[]>([]);
  const [loading, setLoading] = useState(false);
  const [isMenuOpen, setIsMenuOpen] = useState(false);
  const [expandedGroups, setExpandedGroups] = useState<Set<string>>(new Set(['INFO']));
  const [isVisible, setIsVisible] = useState(true);
  const [lastScrollY, setLastScrollY] = useState(0);
  const scrollContainerRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (externalPostId) {
      handleExternalPost(externalPostId);
    }
  }, [externalPostId]);

  const handleExternalPost = async (postId: string) => {
    setLoading(true);
    try {
      const detail = await getPostDetail(postId);
      if (detail) {
        setSelectedPost(detail);
        const postComments = await getCommentsByPost(postId);
        setComments(postComments);
        setView('DETAIL');
      }
    } catch (e) {
      console.error(e);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    localStorage.setItem('vq_forum_view', view);
    localStorage.setItem('vq_forum_category', selectedCategory);
  }, [view, selectedCategory]);

  useEffect(() => {
    if (view === 'LIST') {
      loadPosts();
    }
  }, [selectedCategory, view]);

  const toggleGroup = (groupId: string) => {
    setExpandedGroups(prev => {
      const next = new Set(prev);
      if (next.has(groupId)) {
        next.delete(groupId);
      } else {
        next.add(groupId);
      }
      return next;
    });
  };

  const loadPosts = async () => {
    setLoading(true);
    try {
      const { posts: fetchedPosts } = await getPostsByCategory(selectedCategory);
      setPosts(fetchedPosts);
    } catch (e: unknown) {
      console.error(e);
      const err = e as { code?: string };
      if (err.code === 'permission-denied') {
        alert(lang === 'ko' ? '寃뚯떆湲??遺덈윭??沅뚰븳???놁뒿?덈떎.' : 'Permission denied to load posts.');
      } else {
        alert(lang === 'ko' ? '寃뚯떆湲??遺덈윭?ㅻ뒗 以??ㅻ쪟媛 諛쒖깮?덉뒿?덈떎.' : 'Error loading posts.');
      }
    } finally {
      setLoading(false);
    }
  };

  const handleScroll = (e: React.UIEvent<HTMLDivElement>) => {
    const currentScrollY = e.currentTarget.scrollTop;
    if (currentScrollY > lastScrollY && currentScrollY > 100) {
      setIsVisible(false);
    } else {
      setIsVisible(true);
    }
    setLastScrollY(currentScrollY);
  };

  const handlePostClick = async (post: CommunityPost) => {
    setLoading(true);
    try {
      const detail = await getPostDetail(post.id!);
      if (detail) {
        setSelectedPost(detail);
        const postComments = await getCommentsByPost(post.id!);
        setComments(postComments);
        setView('DETAIL');
      }
    } catch (e) {
      console.error(e);
    } finally {
      setLoading(false);
    }
  };

  const handleBackToList = () => {
    setView('LIST');
    setSelectedPost(null);
    setIsVisible(true);
  };

  return (
    <div className="flex flex-col h-full bg-white rounded-[32px] overflow-hidden border border-slate-100 shadow-sm relative">
      <div className={`absolute top-0 left-0 right-0 z-50 transition-transform duration-500 ease-in-out ${isVisible ? 'translate-y-0' : '-translate-y-full'}`}>
        <div className="bg-white/90 backdrop-blur-xl border-b border-slate-100 p-4 md:p-6 flex items-center justify-between shadow-sm">
          <div className="flex items-center gap-4">
            <button
              onClick={() => setIsMenuOpen(!isMenuOpen)}
              className={`w-10 h-10 rounded-xl flex items-center justify-center text-white shadow-lg shrink-0 transition-all ${isMenuOpen ? 'bg-slate-800 rotate-90' : 'bg-indigo-600 hover:bg-slate-900'}`}
            >
               <Menu size={22} />
            </button>
            <div className="relative">
              <div className="flex flex-col items-start gap-0.5">
                <div className="flex items-center gap-2">
                  <h2 className="text-xl md:text-2xl font-black text-slate-800 tracking-tight">
                     {view === 'LIST' ? getCategoryName(selectedCategory, lang) : (view === 'WRITE' ? (lang === 'ko' ? '寃뚯떆湲 ?묒꽦' : 'New Post') : (lang === 'ko' ? '?곸꽭蹂닿린' : 'Detail'))}
                  </h2>
                </div>
              </div>

              {isMenuOpen && view === 'LIST' && (
                <>
                  <div className="fixed inset-0 z-40" onClick={() => setIsMenuOpen(false)} />
                  <div className="absolute top-full left-0 mt-4 w-72 bg-white rounded-3xl shadow-2xl border border-slate-100 overflow-hidden z-50 animate-in fade-in slide-in-from-top-4 duration-200">
                    <div className="p-2 space-y-4 max-h-[80vh] overflow-y-auto no-scrollbar">
                      {CATEGORY_GROUPS.map(group => {
                        const isExpanded = expandedGroups.has(group.id);
                        return (
                          <div key={group.id} className="space-y-1">
                            <button
                              onClick={(e) => {
                                e.stopPropagation();
                                toggleGroup(group.id);
                              }}
                              className="w-full flex items-center justify-between px-4 py-2 text-[10px] font-black text-slate-400 uppercase tracking-widest border-b border-slate-50 mb-1 hover:bg-slate-50 transition-colors rounded-lg group/header"
                            >
                              <div className="flex items-center gap-2">
                                {group.icon}
                                {lang === 'ko' ? group.label_ko : group.label_en}
                              </div>
                              <ChevronDown size={12} className={`transition-transform duration-300 ${isExpanded ? 'rotate-180' : ''}`} />
                            </button>

                            {isExpanded && (
                              <div className="animate-in fade-in slide-in-from-top-1 duration-200">
                                {group.items.map(cat => (
                                  <button
                                    key={cat.id}
                                    onClick={() => {
                                      setSelectedCategory(cat.id);
                                      setIsMenuOpen(false);
                                    }}
                                    className={`w-full text-left px-4 py-3 rounded-2xl flex items-center justify-between transition-all ${
                                      selectedCategory === cat.id
                                      ? 'bg-indigo-600 text-white shadow-lg'
                                      : 'text-slate-600 hover:bg-slate-50 active:scale-95'
                                    }`}
                                  >
                                    <div className="flex items-center gap-3">
                                      <span className="text-lg">{cat.icon}</span>
                                      <span className="font-bold text-sm">{(cat as any)[`name_${lang}` as 'name_ko' | 'name_en']}</span>
                                    </div>
                                    {selectedCategory === cat.id && <Zap size={14} className="animate-pulse" />}
                                  </button>
                                ))}
                              </div>
                            )}
                          </div>
                        );
                      })}
                    </div>
                  </div>
                </>
              )}
            </div>
          </div>

          <div className="flex items-center gap-2">
             {view === 'LIST' && (
               <button onClick={() => setView('WRITE')} className="bg-indigo-600 text-white p-2.5 md:px-5 md:py-2.5 rounded-xl font-black text-sm hover:bg-slate-900 transition-all shadow-lg flex items-center gap-2">
                 <PenSquare size={16} />
                 <span className="hidden md:inline">{lang === 'ko' ? '湲?곌린' : 'Write'}</span>
               </button>
             )}
             {(view === 'DETAIL' || view === 'WRITE') && (
               <button onClick={handleBackToList} className="bg-white border border-slate-200 text-slate-600 px-4 py-2.5 rounded-xl font-black text-sm hover:bg-slate-50 transition-all flex items-center gap-2">
                 <ArrowLeft size={16} />
                 <span className="hidden md:inline">{lang === 'ko' ? '紐⑸줉?쇰줈' : 'Back'}</span>
               </button>
             )}
          </div>
        </div>
      </div>

      <div ref={scrollContainerRef} onScroll={handleScroll} className="flex-1 overflow-y-auto no-scrollbar pt-24 md:pt-28">
        {view === 'LIST' && (
          <div className="flex flex-col h-full">
            <div className="flex-1 pb-20">
              {loading && posts.length === 0 ? (
                <div className="flex items-center justify-center h-64">
                   <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-indigo-600" />
                </div>
              ) : posts.length === 0 ? (
                <div className="flex flex-col items-center justify-center h-[50vh] text-slate-300">
                   <MessageSquare size={48} className="mb-4 opacity-10" />
                   <p className="font-bold text-slate-400 capitalize">{lang === 'ko' ? '寃뚯떆臾쇱씠 ?놁뒿?덈떎.' : 'No posts found.'}</p>
                </div>
              ) : (
                <div className="divide-y divide-slate-50">
                  {posts.map(post => (
                    <div key={post.id} onClick={() => handlePostClick(post)} className="p-6 md:p-8 hover:bg-slate-50 cursor-pointer transition-colors group relative flex gap-6">
                      <div className="flex-1">
                         <div className="flex justify-between items-start mb-2">
                            <h4 className="text-lg md:text-xl font-black text-slate-800 group-hover:text-indigo-600 transition-colors line-clamp-1 pr-6">
                               <span className="mr-2 text-xl align-middle" title={post.originalLang}>{getFlagEmoji(post.originalLang || 'ko')}</span>
                               {post.title}
                            </h4>
                            {post.commentCount > 0 && <span className="bg-rose-50 text-rose-500 text-[10px] font-black px-2 py-0.5 rounded-md self-start">{post.commentCount}</span>}
                         </div>

                         <div className="flex items-center gap-4 text-xs font-bold text-slate-400">
                            <div className="flex items-center gap-1">
                                <div className="w-5 h-5 rounded-full bg-slate-100 overflow-hidden flex items-center justify-center">
                                   {post.authorAvatar ? <img src={post.authorAvatar} alt="av" className="w-full h-full object-cover" /> : <User size={12} />}
                                </div>
                                <span className="text-slate-600">{post.authorName}</span>
                            </div>
                            <div className="flex items-center gap-1 ml-auto"><Eye size={12} /> {post.viewCount}</div>
                         </div>
                      </div>

                      {/* ?몃꽕???대?吏 ?쒖떆 */}
                      {post.mediaUrls && post.mediaUrls.length > 0 && (
                         <div className="w-20 h-20 md:w-24 md:h-24 rounded-2xl overflow-hidden bg-slate-100 shrink-0 shadow-sm transition-transform group-hover:scale-105">
                            <img src={post.mediaUrls[0]} alt="thumb" className="w-full h-full object-cover" />
                         </div>
                      )}
                    </div>
                  ))}
                </div>
              )}
            </div>

            <div className="w-full pb-8 px-4 md:px-8 max-w-4xl mx-auto">
               <PcAdSlot variant="horizontal" className="w-full shadow-sm rounded-3xl overflow-hidden border border-slate-100/50" />
            </div>
          </div>
        )}

        {view === 'DETAIL' && selectedPost && (
          <PostDetailView
            post={selectedPost}
            comments={comments}
            firebaseUser={firebaseUser}
            lang={lang}
            onCommentAdded={async () => {
               const updatedComments = await getCommentsByPost(selectedPost.id!);
               setComments(updatedComments);
            }}
          />
        )}

        {view === 'WRITE' && (
          <PostWriteView
            lang={lang}
            category={selectedCategory}
            firebaseUser={firebaseUser}
            onSuccess={handleBackToList}
          />
        )}
      </div>
    </div>
  );
};

// VideoEmbedList???덇굅??寃뚯떆遺덉슜?대?濡?Tiptap 湲곕컲 湲?먯꽌??HTML ??iframe?쇰줈 ?泥대맗?덈떎.
const VideoEmbedList = ({ content }: { content: string }) => {
  if (content.startsWith('<')) return null; // Tiptap HTML? ?먯껜 iframe ?ы븿
  const youtubeRegex = /(?:https?:\/\/)?(?:www\.|m\.)?(?:youtube\.com\/(?:watch\?v=|embed\/|shorts\/|live\/)|youtu\.be\/|youtube-nocookie\.com\/embed\/)([a-zA-Z0-9_-]{11})/g;
  const ytMatches = Array.from(content.matchAll(youtubeRegex));
  if (ytMatches.length === 0) return null;

  return (
    <div className="mt-8 space-y-6">
      {ytMatches.map((match, i) => (
        <div key={`yt-${i}`} className="aspect-video rounded-[32px] overflow-hidden bg-slate-100 shadow-2xl border border-slate-200">
          <iframe width="100%" height="100%" src={`https://www.youtube.com/embed/${match[1]}`} frameBorder="0" allowFullScreen />
        </div>
      ))}
    </div>
  );
};

const RichTextRenderer = ({ content, className }: { content: string, className?: string }) => {
  if (!content) return null;
  let html = content;

  // ?덇굅???띿뒪??湲곕컲 蹂??(?섏쐞 ?명솚??
  if (!content.startsWith('<')) {
    html = content
      .replace(/&/g, '&amp;')
      .replace(/</g, '&lt;')
      .replace(/>/g, '&gt;')
      .replace(/\n/g, '<br />')
      .replace(/\[B\](.*?)\[\/B\]/gi, '<strong>$1</strong>')
      .replace(/\[COLOR:([#a-zA-Z0-9]+)\](.*?)\[\/COLOR\]/gi, '<span style="color: $1">$2</span>')
      .replace(/\[IMG:(.*?)\]/gi, '<img src="$1" style="width: 100%; border-radius: 40px; margin: 24px 0;" />');
  }

  return (
    <div 
      className={`prose prose-slate max-w-none 
                  prose-img:rounded-[32px] prose-img:shadow-2xl prose-img:mx-auto prose-img:my-10
                  prose-headings:font-black prose-p:font-medium prose-p:leading-relaxed
                  prose-a:text-indigo-600 prose-blockquote:border-l-4 prose-blockquote:border-indigo-600 prose-blockquote:bg-indigo-50 prose-blockquote:p-6 prose-blockquote:rounded-r-2xl
                  ${className || ''}`} 
      dangerouslySetInnerHTML={{ __html: html }} 
    />
  );
};

const TranslateButton = ({ originalText, targetLang, onTranslate, isHtml = false }: { originalText: string; targetLang: string; onTranslate: (translated: string) => void; isHtml?: boolean }) => {
  const [translating, setTranslating] = useState(false);
  const [translated, setTranslated] = useState(false);

  const handleTranslate = async (e: React.MouseEvent) => {
    e.stopPropagation();
    if (translated) {
        onTranslate(''); 
        setTranslated(false);
        return;
    }

    const userSavedKey = localStorage.getItem('vq_gemini_key');
    if (!userSavedKey) {
        alert(targetLang === 'ko' ? '?ㅼ젙?먯꽌 Gemini API ?ㅻ? ?깅줉?댁빞 踰덉뿭 湲곕뒫???ъ슜?????덉뒿?덈떎.' : 'Please register your Gemini API key in settings to use translation.');
        return;
    }

    setTranslating(true);
    try {
        const result = await translateContent(originalText, targetLang, getActiveApiKey(userSavedKey, false, 0)!, isHtml);
        onTranslate(result);
        setTranslated(true);
    } catch (err: unknown) {
        console.error('Translation error:', err);
        const errorMsg = err instanceof Error ? err.message : 'Unknown translation error occurred';
        alert(errorMsg);
    } finally {
        setTranslating(false);
    }
  };

  return (
    <button 
      onClick={handleTranslate}
      disabled={translating}
      className={`inline-flex items-center gap-1.5 px-3 py-1.5 rounded-lg text-[10px] font-black transition-all border shrink-0
        ${translated 
          ? 'bg-indigo-600 border-indigo-600 text-white shadow-lg shadow-indigo-200' 
          : 'bg-white border-slate-200 text-slate-500 hover:border-indigo-300 hover:text-indigo-600'
        } ${translating ? 'opacity-50 cursor-wait' : ''}`}
    >
      <Globe size={12} className={translating ? 'animate-spin' : ''} />
      {translating ? (targetLang === 'ko' ? '踰덉뿭 以?..' : 'Translating...') : 
       translated ? (targetLang === 'ko' ? '?먮Ц蹂닿린' : 'Show Original') : 
       (targetLang === 'ko' ? 'AI 踰덉뿭' : 'AI Translate')}
    </button>
  );
};

const CommentItem = ({ comment, lang }: { comment: CommunityComment & { authorName?: string; authorAvatar?: string; createdAt?: any }; lang: string }) => {
  const [translatedContent, setTranslatedContent] = useState('');

  return (
    <div className="flex gap-4 p-6 bg-slate-50 rounded-[28px]">
      <div className="w-12 h-12 rounded-[20px] bg-white overflow-hidden shrink-0 flex items-center justify-center border border-slate-100 shadow-sm">
        {comment.authorAvatar ? <img src={comment.authorAvatar} alt="av" className="w-full h-full object-cover" /> : <User size={24} className="text-slate-200" />}
      </div>
      <div className="flex-1 space-y-2">
        <div className="flex items-center justify-between">
          <span className="font-black text-slate-900 block">{comment.authorName}</span>
          <div className="text-[10px] text-slate-400 font-bold uppercase">
            {comment.createdAt?.toDate ? comment.createdAt.toDate().toLocaleString() : ''}
          </div>
        </div>
        <div className="text-sm md:text-base text-slate-600 font-medium leading-relaxed break-all">
          {translatedContent || comment.content}
        </div>
        <div className="pt-2">
          <TranslateButton 
            originalText={comment.content} 
            targetLang={lang} 
            onTranslate={setTranslatedContent} 
          />
        </div>
      </div>
    </div>
  );
};

const PostDetailView = ({ post, comments, firebaseUser, lang, onCommentAdded }: {
  post: CommunityPost;
  comments: CommunityComment[];
  firebaseUser: { uid: string; displayName?: string | null; photoURL?: string | null; [key: string]: unknown } | null;
  lang: string;
  onCommentAdded: () => void;
}) => {
  const [commentText, setCommentText] = useState('');
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [translatedTitle, setTranslatedTitle] = useState('');
  const [translatedContent, setTranslatedContent] = useState('');

  const handleSubmitComment = async () => {
    if (!firebaseUser || !commentText.trim() || !post.id) return;
    setIsSubmitting(true);
    try {
      await createComment(post.id, {
        content: commentText,
        authorId: firebaseUser.uid,
        authorName: firebaseUser.displayName || 'Guest',
        authorAvatar: firebaseUser.photoURL || '',
      });
      setCommentText('');
      onCommentAdded();
    } catch (e) {
      console.error(e);
    } finally {
      setIsSubmitting(false);
    }
  };

  return (
    <div className="p-6 md:p-12 max-w-4xl mx-auto space-y-12 pb-32">
        <div className="space-y-4">
            <h3 className="text-3xl md:text-4xl font-black text-slate-800 leading-tight">
                <span className="mr-3 text-4xl align-middle" title={post.originalLang}>{getFlagEmoji(post.originalLang || 'ko')}</span>
                {translatedTitle || post.title}
            </h3>
            <TranslateButton 
              originalText={post.title} 
              targetLang={lang} 
              onTranslate={setTranslatedTitle} 
            />
        </div>
        <div className="flex items-center gap-4 text-sm font-bold text-slate-400 border-b border-slate-50 pb-8">
            <div className="flex items-center gap-3">
               <div className="w-10 h-10 rounded-2xl bg-indigo-50 overflow-hidden flex items-center justify-center">
                  {post.authorAvatar ? <img src={post.authorAvatar} alt="av" className="w-full h-full object-cover" /> : <User size={20} />}
               </div>
               <div>
                 <div className="text-slate-900 font-black">{post.authorName}</div>
                 <div className="text-[10px] text-slate-400 uppercase">{post.createdAt?.toDate ? post.createdAt.toDate().toLocaleString() : ''}</div>
               </div>
            </div>
            <div className="flex items-center gap-2 ml-auto">
               <Eye size={14} /> <span>{post.viewCount}</span>
            </div>
        </div>
        <div className="text-lg md:text-xl text-slate-700 font-medium leading-relaxed space-y-6">
